proof fn phi_1_mod_mult_zero_implies_mod_zero_external_body(a: nat, b: nat, c: nat)
    requires
        aligned(a, b * c),
        b > 0,
        c > 0,
    ensures
        aligned(a, b),
{
    mod_mult_zero_implies_mod_zero(a, b, c);
}

proof fn phi_2_aligned_product_implies_factor(base: nat, entry_size: nat, a: nat)
    requires
        entry_size > 0,
        a > 0,
        aligned(base, entry_size * a),
    ensures
        aligned(base, entry_size),
{
    mod_mult_zero_implies_mod_zero(base, entry_size, a);
}

proof fn phi_3_aligned_product_implies_second_factor(a: nat, b: nat, c: nat)
    requires
        aligned(a, b * c),
        b > 0,
        c > 0,
    ensures
        aligned(a, c),
{
    assert(b * c == c * b) by (nonlinear_arith);
    mod_mult_zero_implies_mod_zero(a, c, b);
}

